function displayResults(e,t){const n=document.getElementById("results");if(!n){console.error("Search results container is missing in the DOM");return}if(e.length){let s="";for(const o in e){const n=t[e[o].ref];s+='<div class="card"><a href="'+n.url+'"><div class="text"><h2>'+n.title+"</h2>",s+='<p class="small">'+n.content.substring(0,150)+"...</p></a></div></div>"}n.innerHTML=s}else n.innerHTML="No results found."}const params=new URLSearchParams(window.location.search),query=params.get("query");if(query){document.getElementById("search-input").setAttribute("value",query);const e=lunr(function(){this.use(lunr.multiLanguage("en","ja")),this.ref("id"),this.field("title",{boost:15}),this.field("tags"),this.field("content",{boost:10});for(const e in window.store)this.add({id:e,title:window.store[e].title,tags:window.store[e].category,content:window.store[e].content})}),t=e.search(query);displayResults(t,window.store)}